<template>
  <div style="height: 100%;">

    <!-- 大致总体 -->
    <el-container>
      <!-- 头部 -->
      <el-header>
        <div class="header-left">
          <img src="../assets/222.jpg" alt="">
          <div class="title">电商后台管理系统</div>
        </div>
        <el-button type="info" @click="open()">
          退出
        </el-button>
      </el-header>

      <el-container>
        <!-- 左侧菜单 -->
        <el-aside width="200px">

          <el-menu

           :default-active="a"
            class="el-menu-vertical-demo"
             @open="handleOpen"
              @close="handleClose"
            unique-opened
            :collapse="isCollapse">
            <div class="top-bar" @click="isshow()">|||</div>
            <!-- <el-submenu :index="''+item.id" v-for="(item) in list" :key="item.id"> -->
            <el-submenu :index="'/'+item.path" v-for="(item,index) in list" :key="item.id">

              <template slot="title">
                <!-- <i :class="iconobj[item.id]"></i> -->
                <i :class="icon[index]"></i>
                <span slot="title">{{ item.authName}}</span>
              </template>

              <!-- <el-menu-item v-for="(k) in item.children" @click="tiao(k.path)" :key="''+k.id">{{ k.authName }}</el-menu-item> -->
              <el-menu-item :index="`/${k.path}`" v-for="(k) in item.children" @click="tiao(k.path)" :key="''+k.id">
                <i class="el-icon-menu"></i>
                {{ k.authName }}</el-menu-item>

            </el-submenu>

          </el-menu>


        </el-aside>

        <!-- 内容 -->
        <el-main>
          <router-view></router-view>
        </el-main>
      </el-container>
    </el-container>



  </div>
</template>

<script>
  export default {
    data() {
      return {
        isCollapse: false,
        list: [],               //左侧菜单列表
        a: sessionStorage.getItem('activep')||'' ,                 //保存左侧菜单的状态
        iconobj:{
          "125":"el-icon el-icon-user-solid",
          "103":"el-icon el-icon-s-goods",
          "101":"el-icon el-icon-question",
          "102":"el-icon el-icon-warning",
          "145":"el-icon el-icon-s-tools"
         },
        icon:["el-icon-user-solid","el-icon-s-help","el-icon-s-goods","el-icon-s-claim","el-icon-s-marketing"]
      };
    },
    created() {

    },
    mounted() {
      this.menu()
    },
    methods: {
      handleOpen(key, keyPath) {
        // console.log(key, keyPath);
        // keyPath="/index"+keyPath
        // this.$router.push("'/index'+/keyPath")
      },
      handleClose(key, keyPath) {
        // console.log(key, keyPath);
      },
      async menu() {
        let { data } = await this.$http.get('/menus')
        this.list = data.data
        // console.log(this.list)

      },
      isshow() {
        this.isCollapse = !this.isCollapse
      },
      tiao(i) {
        // console.log(i)
        this.a = '/' + i
        sessionStorage.setItem('activep',this.a)
        // console.log(typeof this.a)
        this.$router.push('/index/' + i)
      },
      open() {
        this.$confirm('确定退出吗？', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          this.$message({
            type: 'success',
            message: '退出成功!'
          });
          sessionStorage.clear()
          this.$router.push('/login')
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消退出'
          });
        });
      }
    }
  };
</script>

<style scoped>
  .el-container {
    height: 100%;
  }

  .el-header,
  .el-footer {
    background-color: #373d41;
    /* color: #333;
    text-align: center;
    line-height: 60px; */
    padding: 0 20px;
    box-sizing: border-box;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    background-color: #373d41;
    justify-content: space-between;
  }

  .el-aside {
    background-color: #333744;
    color: #fff;
    /* text-align: center; */
    /* line-height: 200px; */
    height: 100%;
  }

  .el-menu {
    background-color: #333744;
  }


  .el-main {
    background-color: #E9EEF3;
    color: #333;
    /* text-align: center; */
    /* line-height: 160px; */
    height: 100%;
  }

  body>.el-container {
    margin-bottom: 40px;
  }

  .el-container:nth-child(5) .el-aside,
  .el-container:nth-child(6) .el-aside {
    line-height: 260px;
  }

  .el-container:nth-child(7) .el-aside {
    line-height: 320px;
  }

  .header-left {
    /* width: 400px; */
    display: flex;
    align-items: center;
  }

  .header-left img {
    width: 61px;
    height: 56px;
    margin-right: 15px;
  }

  .title {
    font-size: 22px;
    color: #fff;
  }

  .el-button--info {
    color: #FFF;
    background-color: #909399;
    border-color: #909399;
  }

  .el-button {
    display: inline-block;
    line-height: 1;
    white-space: nowrap;
    cursor: pointer;
    background: #A6A9AD;
    border: 1px solid #DCDFE6;
    /* color: #606266; */
    /* -webkit-appearance: none; */
    text-align: center;
    /* -webkit-box-sizing: border-box; */
    box-sizing: border-box;
    outline: 0;
    margin: 0;
    /* -webkit-transition: .1s; */
    transition: .1s;
    font-weight: 500;
    padding: 12px 20px;
    font-size: 14px;
    border-radius: 4px;
  }

  .el-menu-vertical-demo:not(.el-menu--collapse) {
    width: 200px;
    min-height: 400px;
  }

  .top-bar {
    background-color: #4a5064;
    color: #fff;
    font-size: 12px;
    text-align: center;
    line-height: 22px;
    cursor: pointer;
    letter-spacing: .12em;
  }
</style>